import{_ as a}from"./BdBVFdDT.js";import{p as t,_ as i,c as n,a as r,o}from"./BAnZIRC2.js";import{u as s}from"./CGYW6dQL.js";const d=t("/assets/images/african-american-boy.webp"),c={id:"main",class:"white-paper"},h={__name:"white-paper-article",setup(l){return s({title:"Dicapta White Papers | In-Depth Insights on Accessibility Technology and Media",meta:[{hid:"description",name:"description",content:"Explore Dicapta's white papers for in-depth insights on accessibility technology, media solutions, and industry best practices. Learn more about our impact."}]}),(p,e)=>(o(),n("main",c,e[0]||(e[0]=[r('<p class="white-paper__date blue-background" data-v-bbda594a>12 MAY 2024</p><section class="blue-background white-paper__first-section" data-v-bbda594a><h1 class="white-paper__title" data-v-bbda594a> Embracing Diversity in Audio Description: A Paradigm Shift for Inclusivity </h1></section><section data-v-bbda594a><h2 data-v-bbda594a>Abstract</h2><p data-v-bbda594a> This white paper explores the evolving paradigm in audio description, emphasizing including racial and ethnic characteristics when describing individuals/people in media. It aims to provide a comprehensive guide on best practices, highlighting the importance of representation and empathy, and challenging stereotypes through thoughtful and detailed audio descriptions. </p><h2 data-v-bbda594a>Introuction</h2><p data-v-bbda594a> The art of Audio Description is based on the textual or verbal representation of visual elements in images, videos, movies, dances, plays, and so on (media, for this paper). This representation allows individuals who can&#39;t access or decode visual information to enjoy, comprehend, and actively discuss any media experience. Serving primarily the needs of individuals who are blind, this evolving art has enriched the media experience for children and adults with autism, learning disabilities, as well as for individuals tailoring their film and TV scripting skills or for those learning a different language. </p><p data-v-bbda594a> In multiple fields, from education to entertainment, audio description has traditionally skirted around explicitly mentioning race and ethnicity. However, society&#39;s increasing diversity awareness and acceptance calls for a more inclusive approach that emphasizes visibility and representation in media. This document examines the shift towards acknowledging racial and ethnic identities in audio descriptions, underpinning its necessity in creating a diverse and inclusive media landscape. </p></section><section class="blue-background" data-v-bbda594a><h2 data-v-bbda594a>Background and Traditional Practices</h2><p data-v-bbda594a> Historically, audio description guidelines recommended avoiding mentioning race or ethnicity unless pivotal to the plot or context. This practice stemmed from a desire to promote inclusivity by not highlighting differences. However, this approach often led to underrepresentation and a need for more visibility for diverse groups. </p><p data-v-bbda594a> Describing characters is always a challenge for audio-describers. The racial and ethnic identity of a person is a social construction, so it becomes a highly subjective aspect, and its definition and categorization may vary according to the cultural and geographical context. For this reason, these characteristics have been traditionally omitted in audio descriptions. </p><h3 data-v-bbda594a>Distinguishing Race and Ethnicity</h3><p data-v-bbda594a> Understanding the distinction between race and ethnicity is critical in audio descriptions. Race refers to physical attributes such as skin color, facial features, and hair texture and is often associated with biological factors. On the other hand, ethnicity is a more complex and multifaceted concept, encompassing cultural, linguistic, and communal affinities that bind individuals into distinct groups. </p><p data-v-bbda594a> The Merriam-Webster dictionary offers the following summary about the use of both words: the term race is understood today as primarily a sociological designation that identifies a group sharing some outward physical characteristics and some commonalities of culture and history, while ethnicity is a word for something you acquire based on where your family is from and the group which you share cultural, traditional, and familial bonds and experiences with. The end result: people may have racial similarity but ethnic dissimilarity. </p><p data-v-bbda594a> Aligned with that, it is important to emphasize that when describing, race may be detailed by painting with words physical attributes, but ethnicity belongs to a cultural interpretation made by whoever is describing, unintentionally adding their cultural identity to the mix. </p><h3 data-v-bbda594a>Race in the traditional guidelines for audio description</h3><p data-v-bbda594a> Until recently, guidelines validated by the audio description industry recommended not including racial or ethnicity descriptions, except for specific exceptions. Regarding this subject, the <a href="https://drive.google.com/file/d/1CE_5Mgc-26QHt_q3Nzo5lhT-oc6vPkri/view" target="_blank" rel="noopener noreferrer" data-v-bbda594a>Post Production Described Best Practices by AMI in Canada</a> states, &quot;An identification of characters by race, ethnic origin or disability is not required unless there is relevancy to plot, motivation or background, or if meaningful information is being communicated visually and would be otherwise unavailable&quot;; similarly, Dicapta&#39;s AD guidelines used to state, &quot;Only when the context and subject matter warrant it, it is worthwhile to clarify or mention race; to do so, use terms such as black race, white race, or Asian features.” </p><p data-v-bbda594a> Even though the ideal inclusive scenario would be, precisely, not to talk, and discuss race differences, today, as part of an effort to reach that goal, highlighting, remarking, and concisely mentioning race differences when describing is essential for the comprehension of the context, and encouraging diversity awareness, as well as for promoting inclusion and equality. </p><h2 data-v-bbda594a>The Paradigm Shift: Importance of Including Race and Ethnicity</h2><img class="white-paper__image-left" src="'+a+'" alt="Two illustrations in one image: Image on the left. A young girl with light brown skin and long, dark, curly hair sits at a desk, reading a large book. She wears a bright yellow dress adorned with a sunflower pattern. Her eyes sparkle. The room is warmly illuminated, featuring a globe, a telescope, and posters in the background. Image on the right. A boy with dark brown skin and short, tightly coiled hair operates a toy car outside. He sports a red hoodie paired with blue jeans. He smiles. In the background are other children. A playground is in the distance." loading="lazy" width="468" height="468" data-v-bbda594a><p data-v-bbda594a> A shift in perspective has emerged, recognizing that omitting racial and ethnic descriptions can inadvertently contribute to exclusion. By incorporating these elements, audio descriptions can foster diversity, promote empathy, and challenge stereotypes while building a new society. This section delves into the reasons behind this paradigm shift, especially applied to children&#39;s media. </p><p data-v-bbda594a> Media can significantly influence children&#39;s perceptions and attitudes, including their views on race, gender, culture, and social norms. By ensuring that children&#39;s media is inclusive and diverse, we can encourage the development of a more accepting and understanding society. It helps in normalizing diversity and inclusivity as part of everyday life. </p><q data-v-bbda594a>Why is this discussion important? Because what is not described does not exist for the viewer</q><h4 data-v-bbda594a>- Representation of diversity</h4><p data-v-bbda594a> Children need to see their own racial and ethnic diversity reflected in the media so they can feel represented and valued. By showing characters from different racial and ethnic backgrounds, children can identify with the characters and feel part of the story. This promotes a sense of inclusion and belonging. A good example of reactions from kids can be found following this link: <a href="https://www.youtube.com/watch?v=GsSJLK3WW54" target="_blank" rel="noopener noreferrer" data-v-bbda594a>Black Kids&#39; Heartwarming Reactions to &#39;The Little Mermaid&#39;</a>. </p><h4 data-v-bbda594a>- Promoting empathy and acceptance</h4><p data-v-bbda594a> Being exposed to racial diversity from an early age may help children develop empathy and understanding for people who are equal but different from them. By seeing and learning about different cultures and races, children can develop a natural view and positive attitude toward diversity and learn to accept and respect others. </p><h4 data-v-bbda594a>- Challenging stereotypes, prejudice, and discrimination</h4><p data-v-bbda594a> Common stereotypes and prejudices are challenged by showing characters of different races realistically and positively. Stereotypes can limit children&#39;s perspectives and perpetuate prejudice and discrimination. <a href="https://www.youtube.com/watch?v=QRZPw-9sJtQ" target="_blank" rel="noopener noreferrer" data-v-bbda594a>Follow the link to see the effects of racism on children during a Doll test.</a></p><q data-v-bbda594a>“By age eight, racial attitudes are well developed and tend to stay the same unless a child has significant experiences and adult guidance that directly contradict the prevailing social attitudes” (Hindley &amp; Edwards, 2017)</q><p data-v-bbda594a> Including and showing diversity in audiovisual content accurately and authentically encourages an inclusive perspective, which helps break down negative stereotypes. </p><h3 data-v-bbda594a>Children&#39;s perception of racial diversity</h3><p data-v-bbda594a> The way that children perceive racial diversity can be different depending on their level of understanding, previous experiences, and the information provided to them. This explains why audio description is such an important source of educational information for blind children, as it helps to provide them with the same experience as sighted children. </p><p data-v-bbda594a> Although blind children cannot see physical differences in people&#39;s race, <strong data-v-bbda594a>they can develop an understanding and appreciation of racial diversity through other means</strong>, such as verbal descriptions, language, accents, and social interactions. </p><h4 data-v-bbda594a>- Verbal descriptions</h4><p data-v-bbda594a> Children, including those who are blind, can learn about racial diversity through detailed verbal descriptions of people&#39;s physical characteristics. They can hear about variations in skin tone, hair color, texture, face shape, and other distinguishing features commonly used to describe race. </p><h4 data-v-bbda594a>- Language and accents</h4><p data-v-bbda594a> Children, including those who are blind, may also notice differences in the sounds and accents of people&#39;s voices, which may be associated with a particular race or ethnicity. These elements can provide clues to cultural and ethnic diversity in their environment. </p><h4 data-v-bbda594a>- Social interaction</h4><img class="white-paper__image-right" src="'+d+'" alt="Indoors. An African American boy with black curly hair is assembling a robot from a science kit. He is wearing a light blue t-shirt with a cartoon rocket ship design. The boy is seated at a wooden table. He has a focused expression and looks at the robot pieces on the table while he lifts a white and long piece from the table. The wall behind him is adorned with posters and a bookshelf with books." loading="lazy" width="468" height="468" data-v-bbda594a><p data-v-bbda594a> Children, including those who are blind, interact with different people in their environment, such as family members, friends, classmates, and community members. Through these interactions, they can learn about racial diversity through the experiences, perspectives, and cultural backgrounds of the people with whom they interact. </p><p data-v-bbda594a> It is important to notice that a child&#39;s experience interpreting racial diversity can be unique and personal. Each child has strengths, interests, and ways of perceiving and understanding the world. Promoting an inclusive environment where all identities and cultures are celebrated and valued is critical to supporting understanding and respect for racial diversity. </p><h2 data-v-bbda594a> Recommended procedure when audio describing for the media industry </h2><h3 data-v-bbda594a> 1. Educate and introduce content creators to the basics of AD and the needs of children with visual disabilities from the inception of the series/educational content. </h3><p data-v-bbda594a> The video “<a href="https://www.youtube.com/watch?v=MEkgKtqIP2k&amp;t=26s" target="_blank" rel="noopener noreferrer" data-v-bbda594a>Join the Audio Description Movement - The Directors Have the Floor</a>” by Dicapta can help introduce the concept of AD among content creators. Click on the name of the video to access it. You can also create a basic resource kit to share with them or schedule an awareness workshop with experts in the field. </p><h3 data-v-bbda594a>2. Request character descriptions from content creators.</h3><p data-v-bbda594a> This is an editorial decision, and content creators should provide the Audio Description team with the specific details they wish to highlight for the audience. Dicapta has created a form for that purpose. Follow the link to review <a href="https://docs.google.com/forms/d/e/1FAIpQLSdfUl-sDMw5o0Rx2oauX1YwgIU51l_Fn2eD_XxWpsJMwU1e7g/viewform" target="_blank" rel="noopener noreferrer" data-v-bbda594a>the character&#39;s visual details to consider when describing</a>, and feel free to use it as a guide. </p><h3 data-v-bbda594a> 3. Consult with experts or represented community members to ensure accurate description. </h3><p data-v-bbda594a> Consulting with people with first-hand knowledge or experience related to race and ethnicity will improve the final product. Their input can provide valuable information and help avoid potential stereotypes or bias. See references for some examples. </p><h3 data-v-bbda594a> 4. Assess the significance of each character within the specific context to determine which aspects should be described and which should not. </h3><p data-v-bbda594a> Evaluating how the character&#39;s physical characteristics contribute to their identity and the story is critical. This will help guide the decision-making process on what aspects to emphasize in the Audio Description. </p><h3 data-v-bbda594a> 5. Collaboration between the content creators and the AD team will ensure the accurate portrayal of race and ethnicity in the audiovisual content. </h3><p data-v-bbda594a> Solicit feedback and review of the Audio Description script from the content creator to facilitate this process. </p><h3 data-v-bbda594a> 6. Testing the material with the target audience to make necessary changes or adjustments. Seek feedback and engage in dialogue with consumers. For example, blind children, their families, and the broader blind community. </h3><p data-v-bbda594a> It is important to work together on this last step, which will provide additional feedback on race and ethnicity and the quality of the Audio Description produced. Dicapta actively involves blind children, their families, and representatives of the blind community in developing and improving audio description. Their perspectives have been invaluable for the production team and will be invaluable to the content creator to ensure that the media content is inclusive and meets their needs. </p></section><section data-v-bbda594a><h2 data-v-bbda594a>Conclusions</h2><p data-v-bbda594a> The journey towards inclusion has led us through changing norms and emerging best practices. In this white paper, we&#39;ve explored the vital paradigm shift redefining how we approach the portrayal of race and ethnicity in audio description —a shift from omission to inclusion, from invisibility to visibility. </p><p data-v-bbda594a> The importance of this shift cannot be overstated. By consciously incorporating racial and ethnic diversity in our audio description field, we construct a new society by empowering children to perceive and appreciate a spectrum of human experiences. This enriches their understanding and fosters a more inclusive worldview from the earliest stages of development. It is a proactive step towards building a society that values every individual and celebrates diversity as a collective strength. </p><p data-v-bbda594a> The recommended practices outlined in this paper serve as a blueprint for content creators and audio describers. From balanced representation to cultural sensitivity, these guidelines ensure that audio descriptions are accurate, respectful and authentic. </p><p data-v-bbda594a> Finally, our commitment to ongoing collaboration with the blind community, experts, and content creators ensures that audio description remains a dynamic tool that evolves with our social fabric and continues to serve as an agent of change. </p><p data-v-bbda594a> As we look to the future, we aspire to cultivate a media environment that mirrors a society where diversity is not merely included but embraced. A society where every child can navigate the world with confidence and a sense of belonging. We hope this white paper will serve as a stepping stone toward that inclusive and vibrant tomorrow. </p><h3 data-v-bbda594a>Dicapta’s Audio Description Team</h3><p data-v-bbda594a>María-Victoria Díaz, PhD, Andrea Giménez, and Sergio Carrasquilla.</p><p data-v-bbda594a> Note: You can also download the <a href="/assets/pdf/embracing-diversity-in-audio-description.pdf" target="_blank" rel="noopener noreferrer" data-v-bbda594a>PDF version of this white paper</a>. </p></section><section class="blue-background white-paper__last-section" data-v-bbda594a><h2 data-v-bbda594a>References and Bibliography</h2><p data-v-bbda594a> Abu Tair, S., Haider, A. S., &amp; Alkhawaldeh, M. (2023). Verbalizing visual characterizations of race in the audio description of Netflix. British Journal of Visual Impairment, 0(0) <a href="https://doi.org/10.1177/02646196231203594" target="_blank" rel="noopener noreferrer" data-v-bbda594a>https://doi.org/10.1177/02646196231203594</a></p><p data-v-bbda594a> Blakemore, E. (2019, February 22). Race and ethnicity: How are they different? National Geographic, <a href="https://www.nationalgeographic.com/culture/article/race-ethnicity?loggedin=true&amp;rnd=1688215800083" target="_blank" rel="noopener noreferrer" data-v-bbda594a>https://www.nationalgeographic.com/culture/article/race-ethnicity?loggedin=true&amp;rnd=1688215800083</a></p><p data-v-bbda594a> Dunne, L., Kay, V., Boyle, R., Obadan, F. &amp; Lander, V. (2018) ‘I love a curry’: student-teacher discourse around ‘race’ and ethnicity at a UK university, Journal of Education for Teaching, 44:2, 162-174, DOI: 10.1080/02607476.2017.1415514 </p><p data-v-bbda594a> Gómez García, P. (1998). Las ilusiones de la &#39;identidad&#39;. La etnia como pseudoconcepto. Gazeta de Antropología, Nº 14, 1998, Artículo 12. <a href="https://www.ugr.es/~pwlac/G14_12Pedro_Gomez_Garcia.html" target="_blank" rel="noopener noreferrer" data-v-bbda594a>https://www.ugr.es/~pwlac/G14_12Pedro_Gomez_Garcia.html</a></p><p data-v-bbda594a> Hutchinson, R., Thompson, H., Cock, M. (2020, September 16). Describing Diversity. Vocal Eyes, <a href="https://vocaleyes.co.uk/research/describing-diversity/" target="_blank" rel="noopener noreferrer" data-v-bbda594a>https://vocaleyes.co.uk/research/describing-diversity/</a></p><p data-v-bbda594a> Merriam-Webster. (n.d.). The difference between race and ethnicity. Retrieved February 21, 2024, from <a href="https://www.merriam-webster.com/grammar/difference-between-race-and-ethnicityhttps://www.scribbr.com/citation/generator/apa/" target="_blank" rel="noopener noreferrer" data-v-bbda594a>https://www.merriam-webster.com/grammar/difference-between-race-and-ethnicityhttps://www.scribbr.com/citation/generator/apa/</a></p><p data-v-bbda594a> Mukhopadhyay, C., Henze, R. and Moses, Y. (2014). How Real Is Race? A Sourcebook on Race, Culture, and Biology. Lanham: Alta Mira Press. <a href="https://books.google.com.co/books?hl=en&amp;lr=&amp;id=uT6SAgAAQBAJ&amp;oi=fnd&amp;pg=PR5&amp;ots=nl253h9Nkc&amp;sig=XMFABzEINAbePguPEN36N4j7heE&amp;redir_esc=y#v=onepage&amp;q&amp;f=false" target="_blank" rel="noopener noreferrer" data-v-bbda594a>https://books.google.com.co/books?hl=en&amp;lr=&amp;id=uT6SAgAAQBAJ&amp;oi=fnd&amp;pg=PR5&amp;ots=nl253h9Nkc&amp;sig=XMFABzEINAbePguPEN36N4j7heE&amp;redir_esc=y#v=onepage&amp;q&amp;f=false</a></p><p data-v-bbda594a> Shogren, K., Kennedy, W., Dowsett, C., Garnier, M., and Little, T. (2014). Exploring Essential Characteristics of Self-Determination for Diverse Students Using Data from NLTS2. Hammill Institute on Disabilities, Career Development and Transition for Exceptional Individuals 2014, Vol. 37(3) 168–176, <a href="https://files.eric.ed.gov/fulltext/EJ1045522.pdf" target="_blank" rel="noopener noreferrer" data-v-bbda594a>https://files.eric.ed.gov/fulltext/EJ1045522.pdf</a></p><p data-v-bbda594a> Sturdivant, T. (2020). Sociodramatic Play with Racially Diverse Dolls in a Child Development Center. Dimension of Early Childhood, Volume 48/Number 3, 10-14,<a href="https://files.eric.ed.gov/fulltext/EJ1293317.pdf" target="_blank" rel="noopener noreferrer" data-v-bbda594a>https://files.eric.ed.gov/fulltext/EJ1293317.pdf</a></p><p data-v-bbda594a> Suyemoto, K.L.; Curley, M.; Mukkamala, S. What Do We Mean by “Ethnicity” and “Race”? A Consensual Qualitative Research Investigation of Colloquial Understandings. Genealogy 2020, 4, 81.<a href="https://doi.org/10.3390/genealogy4030081" target="_blank" rel="noopener noreferrer" data-v-bbda594a>https://doi.org/10.3390/genealogy4030081</a></p><h3 data-v-bbda594a>Organizations</h3><p data-v-bbda594a> Stanford[1]  Center for Comparative Studies in Race and Ethnicity -<a href="https://ccsre.stanford.edu/" target="_blank" rel="noopener noreferrer" data-v-bbda594a>https://ccsre.stanford.edu/</a></p><p data-v-bbda594a> Perception Institute -<a href="https://perception.org/" target="_blank" rel="noopener noreferrer" data-v-bbda594a>https://perception.org/</a></p><p data-v-bbda594a> OpenStax - Rice University -<a href="https://openstax.org/books/introduction-sociology-3e/pages/11-1-racial-ethnic-and-minority-groups" target="_blank" rel="noopener noreferrer" data-v-bbda594a>https://openstax.org/books/introduction-sociology-3e/pages/11-1-racial-ethnic-and-minority-groups</a></p><p data-v-bbda594a> American Psychological Association - <a href="https://www.apa.org/topics/racism-bias-discrimination" target="_blank" rel="noopener noreferrer" data-v-bbda594a>https://www.apa.org/topics/racism-bias-discrimination</a></p><p data-v-bbda594a> Pew Research Center -<a href="https://www.pewresearch.org/topic/race-ethnicity/" target="_blank" rel="noopener noreferrer" data-v-bbda594a>https://www.pewresearch.org/topic/race-ethnicity/</a></p><h3 data-v-bbda594a>Videos of interest</h3><p data-v-bbda594a> Doll test - The effects of racism on children -<a href="https://www.youtube.com/watch?v=QRZPw-9sJtQ" target="_blank" rel="noopener noreferrer" data-v-bbda594a>https://www.youtube.com/watch?v=QRZPw-9sJtQ</a></p><p data-v-bbda594a> These Twins Show That Race Is A Social Construct | National Geographic -<a href="https://www.youtube.com/watch?v=FS4DGri-NBo" target="_blank" rel="noopener noreferrer" data-v-bbda594a>https://www.youtube.com/watch?v=FS4DGri-NBo</a></p><p data-v-bbda594a> 4- to 6-Year-Olds Review Dolls Of Different Skin Colors | Regardless Of Race - <a href="https://www.youtube.com/watch?v=Q8_EqAWFs4k" target="_blank" rel="noopener noreferrer" data-v-bbda594a>https://www.youtube.com/watch?v=Q8_EqAWFs4k</a></p><p data-v-bbda594a> Dr Kenneth Clark | The Doll Test and Desegregation (1988) - <a href="https://www.youtube.com/watch?v=O-nH8LE4zAU" target="_blank" rel="noopener noreferrer" data-v-bbda594a>https://www.youtube.com/watch?v=O-nH8LE4zAU</a></p></section>',6)])))}},m=i(h,[["__scopeId","data-v-bbda594a"]]);export{m as default};
